import { Router } from 'express';
import { EmployeeController } from './employee.controller.js';
import { validate } from '../../middlewares/validate.js';
import { createEmployeeSchema, updateEmployeeSchema } from './employee.validation.js';
import { authenticate } from '../../middlewares/auth.js';
const router = Router();
router.get('/count', EmployeeController.getCount);
router.post('/', validate(createEmployeeSchema), EmployeeController.create);
router.use(authenticate);
router.get('/', EmployeeController.getAll);
router.get('/:id', EmployeeController.getById);
router.put('/:id', validate(updateEmployeeSchema), EmployeeController.update);
router.delete('/:id', EmployeeController.delete);
export default router;
